"use client"

import * as React from "react"
import type { ColumnDef } from "@gunjo/ui"
import {
  Badge,
  Card,
  CardContent,
  Container,
  DataTable,
  Select,
  SearchInput,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  Statistic,
} from "@gunjo/ui"

import {
  ApplicationDetail,
  SlaBadge,
  StatusIcon,
} from "./ApplicationDetail"
import {
  APP_KINDS,
  APP_STATUSES,
  CURRENT_STAFF,
  NOW,
  SEED_APPLICATIONS,
  calcFee,
  slaState,
  type Application,
  type AppKind,
  type AppStatus,
  type StageId,
} from "./data"

function fmtDateTime(iso: string): string {
  const d = new Date(iso)
  const p = (n: number) => String(n).padStart(2, "0")
  return `${p(d.getMonth() + 1)}/${p(d.getDate())} ${p(d.getHours())}:${p(d.getMinutes())}`
}

const ALL_KINDS = "__all_kinds__"
const ALL_STATUS = "__all_status__"

export default function ApplicationIntakePage() {
  const [apps, setApps] = React.useState<Application[]>(SEED_APPLICATIONS)
  const [selectedId, setSelectedId] = React.useState<string | null>(null)
  const [kindFilter, setKindFilter] = React.useState<string>(ALL_KINDS)
  const [statusFilter, setStatusFilter] = React.useState<string>(ALL_STATUS)
  const [query, setQuery] = React.useState("")

  const selected = apps.find((a) => a.id === selectedId) ?? null

  // ---- mutations (the workflow state machine) ----
  const update = (id: string, fn: (a: Application) => Application) =>
    setApps((prev) => prev.map((a) => (a.id === id ? fn(a) : a)))

  const handleAdvance = (id: string) => (next: AppStatus, stage: StageId) => {
    update(id, (a) => ({
      ...a,
      status: next,
      stages: {
        ...a.stages,
        [stage]: { actor: CURRENT_STAFF, at: new Date().toISOString() },
      },
    }))
  }

  const handleSendBack = (id: string) => (reason: string) => {
    update(id, (a) => ({
      ...a,
      status: "kakunin",
      stages: {
        ...a.stages,
        shinsa: { actor: CURRENT_STAFF, at: new Date().toISOString(), comment: reason },
      },
    }))
  }

  const handleToggleDoc = (id: string) => (doc: string, on: boolean) => {
    update(id, (a) => ({
      ...a,
      verifiedDocs: on
        ? Array.from(new Set([...a.verifiedDocs, doc]))
        : a.verifiedDocs.filter((d) => d !== doc),
    }))
  }

  const handleSetIdMethod = (id: string) => (method: string) =>
    update(id, (a) => ({ ...a, idMethod: method || undefined }))

  const handleSetCopies = (id: string) => (copies: number) =>
    update(id, (a) => ({ ...a, copies }))

  const handleIssue = (id: string) => () =>
    update(id, (a) => {
      const at = new Date().toISOString()
      return {
        ...a,
        status: "kofu_zumi",
        issued: { by: CURRENT_STAFF, at },
        stages: { ...a.stages, kofu: { actor: CURRENT_STAFF, at } },
      }
    })

  // ---- filtering ----
  const filtered = apps.filter((a) => {
    if (kindFilter !== ALL_KINDS && a.kind !== kindFilter) return false
    if (statusFilter !== ALL_STATUS && a.status !== statusFilter) return false
    if (query.trim()) {
      const q = query.trim().toLowerCase()
      const hay = `${a.applicant} ${a.furigana} ${a.receiptNo}`.toLowerCase()
      if (!hay.includes(q)) return false
    }
    return true
  })

  // ---- KPI summary ----
  const openCount = apps.filter((a) => a.status !== "kofu_zumi").length
  const overdueCount = apps.filter(
    (a) => a.status !== "kofu_zumi" && slaState(a.dueAt, NOW) === "overdue"
  ).length
  const atRiskCount = apps.filter(
    (a) => a.status !== "kofu_zumi" && slaState(a.dueAt, NOW) === "at_risk"
  ).length
  const issuedToday = apps.filter((a) => a.status === "kofu_zumi").length

  // ---- columns ----
  const columns: ColumnDef<Application>[] = [
    {
      accessorKey: "receiptNo",
      header: "受付番号",
      cell: ({ row }) => (
        <span className="font-medium tabular-nums">{row.original.receiptNo}</span>
      ),
    },
    {
      id: "kind",
      header: "申請種別",
      accessorFn: (a) => APP_KINDS[a.kind].label,
      cell: ({ row }) => APP_KINDS[row.original.kind].label,
    },
    {
      accessorKey: "applicant",
      header: "申請者",
      cell: ({ row }) => (
        <div className="flex flex-col">
          <span>{row.original.applicant}</span>
          <span className="text-xs text-muted-foreground">{row.original.furigana}</span>
        </div>
      ),
    },
    {
      id: "receivedAt",
      header: "受付日時",
      accessorFn: (a) => a.receivedAt,
      cell: ({ row }) => (
        <span className="tabular-nums">{fmtDateTime(row.original.receivedAt)}</span>
      ),
    },
    {
      id: "status",
      header: "状態",
      accessorFn: (a) => APP_STATUSES[a.status].label,
      cell: ({ row }) => {
        const m = APP_STATUSES[row.original.status]
        return (
          <Badge variant={m.tone} icon={<StatusIcon status={row.original.status} />}>
            {m.label}
          </Badge>
        )
      },
    },
    {
      id: "sla",
      header: "処理期限",
      accessorFn: (a) => new Date(a.dueAt).getTime(),
      cell: ({ row }) =>
        row.original.status === "kofu_zumi" ? (
          <span className="text-xs text-muted-foreground">—</span>
        ) : (
          <div className="flex flex-col gap-1">
            <SlaBadge dueAt={row.original.dueAt} />
            <span className="text-xs text-muted-foreground tabular-nums">
              {fmtDateTime(row.original.dueAt)}
            </span>
          </div>
        ),
    },
  ]

  return (
    <Container size="2xl" as="main" className="py-6">
      <header className="mb-6 flex flex-col gap-1">
        <p className="text-sm text-muted-foreground">みどり市役所 ／ 市民課 窓口</p>
        <h1 className="text-2xl font-bold tracking-tight">申請受付管理</h1>
        <p className="text-sm text-muted-foreground">
          担当：{CURRENT_STAFF}　基準時刻：{fmtDateTime(NOW.toISOString())}
        </p>
      </header>

      {/* KPI */}
      <section aria-label="受付状況サマリー" className="mb-6 grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
        <Statistic label="処理中の申請" value={`${openCount} 件`} />
        <Statistic
          label="期限超過"
          value={`${overdueCount} 件`}
          hint={overdueCount > 0 ? "至急対応してください" : "なし"}
        />
        <Statistic label="期限間近（1時間未満）" value={`${atRiskCount} 件`} />
        <Statistic label="本日交付済" value={`${issuedToday} 件`} />
      </section>

      {/* filters */}
      <Card className="mb-4">
        <CardContent className="flex flex-col gap-3 p-4 sm:flex-row sm:items-end">
          <div className="flex-1">
            <SearchInput
              aria-label="氏名・受付番号で検索"
              placeholder="氏名・ふりがな・受付番号で検索"
              value={query}
              onValueChange={setQuery}
            />
          </div>
          <Select
            label="申請種別"
            value={kindFilter}
            onChange={(e) => setKindFilter(e.target.value)}
            className="sm:w-52"
          >
            <option value={ALL_KINDS}>すべて</option>
            {(Object.keys(APP_KINDS) as AppKind[]).map((k) => (
              <option key={k} value={k}>
                {APP_KINDS[k].label}
              </option>
            ))}
          </Select>
          <Select
            label="状態"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="sm:w-44"
          >
            <option value={ALL_STATUS}>すべて</option>
            {(Object.keys(APP_STATUSES) as AppStatus[]).map((s) => (
              <option key={s} value={s}>
                {APP_STATUSES[s].label}
              </option>
            ))}
          </Select>
        </CardContent>
      </Card>

      {/* queue */}
      <section aria-label="申請受付一覧">
        <DataTable
          columns={columns}
          data={filtered}
          pageSize={10}
          onRowClick={(row) => setSelectedId(row.id)}
          filter={null}
          labels={{
            noResults: "該当する申請はありません。",
            rowsPerPage: "表示件数",
            paginationSummary: (from, to, total) => `${total}件中 ${from}–${to}件`,
          }}
          renderCard={(row) => (
            <button
              type="button"
              onClick={() => setSelectedId(row.id)}
              className="flex w-full flex-col gap-2 rounded-lg border border-border p-3 text-left"
            >
              <div className="flex items-center justify-between gap-2">
                <span className="font-medium tabular-nums">{row.receiptNo}</span>
                <Badge variant={APP_STATUSES[row.status].tone} icon={<StatusIcon status={row.status} />}>
                  {APP_STATUSES[row.status].label}
                </Badge>
              </div>
              <span className="text-sm">{APP_KINDS[row.kind].label}</span>
              <span className="text-sm">
                {row.applicant}
                <span className="ml-1 text-xs text-muted-foreground">{row.furigana}</span>
              </span>
              <div className="flex items-center justify-between gap-2">
                <span className="text-xs text-muted-foreground tabular-nums">
                  受付 {fmtDateTime(row.receivedAt)}
                </span>
                {row.status !== "kofu_zumi" ? <SlaBadge dueAt={row.dueAt} /> : null}
              </div>
            </button>
          )}
        />
      </section>

      {/* detail sheet */}
      <Sheet open={selected !== null} onOpenChange={(open) => !open && setSelectedId(null)}>
        <SheetContent
          side="right"
          className="w-full overflow-y-auto sm:max-w-xl"
          closeLabel="閉じる"
        >
          {selected ? (
            <>
              <SheetHeader>
                <SheetTitle>
                  {selected.applicant} ／ {APP_KINDS[selected.kind].label}
                </SheetTitle>
                <SheetDescription>
                  受付番号 {selected.receiptNo}・部数 {selected.copies}通・手数料{" "}
                  {calcFee(selected.kind, selected.copies).toLocaleString("ja-JP", {
                    style: "currency",
                    currency: "JPY",
                  })}
                </SheetDescription>
              </SheetHeader>
              <div className="mt-4">
                <ApplicationDetail
                  app={selected}
                  onAdvance={handleAdvance(selected.id)}
                  onSendBack={handleSendBack(selected.id)}
                  onToggleDoc={handleToggleDoc(selected.id)}
                  onSetIdMethod={handleSetIdMethod(selected.id)}
                  onSetCopies={handleSetCopies(selected.id)}
                  onIssue={handleIssue(selected.id)}
                />
              </div>
            </>
          ) : null}
        </SheetContent>
      </Sheet>
    </Container>
  )
}

"use client"

import * as React from "react"
import {
  IconArrowBackUp,
  IconArrowRight,
  IconAlertTriangle,
  IconClipboardCheck,
  IconId,
  IconReceipt2,
  IconCircleDot,
  IconUserCheck,
  IconSearch,
  IconRubberStamp,
  IconPackage,
  IconCircleCheck,
} from "@tabler/icons-react"

import {
  ApprovalSteps,
  type ApprovalStep,
  Alert,
  AlertTitle,
  AlertDescription,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Checkbox,
  CoSign,
  MetadataList,
  NumberInput,
  Separator,
  SignedRecord,
  type SignedRecordValue,
  Statistic,
  Textarea,
  formatCurrency,
} from "@gunjo/ui"

import {
  APP_KINDS,
  APP_STATUSES,
  CURRENT_STAFF,
  NOW,
  STAGES,
  calcFee,
  slaState,
  statusToStageIndex,
  type Application,
  type AppStatus,
  type StageId,
} from "./data"

function fmtDateTime(iso: string): string {
  const d = new Date(iso)
  const p = (n: number) => String(n).padStart(2, "0")
  return `${d.getFullYear()}/${p(d.getMonth() + 1)}/${p(d.getDate())} ${p(d.getHours())}:${p(d.getMinutes())}`
}

/** Build the ApprovalSteps step list from an application's current status + records. */
function buildSteps(app: Application): ApprovalStep[] {
  const currentIdx = statusToStageIndex(app.status)
  const sentBack = app.status === "kakunin"
  return STAGES.map((stage, idx) => {
    const rec = app.stages[stage.id]
    let state: ApprovalStep["state"]
    if (sentBack && idx === 2) {
      // 要確認: 書類審査で差戻し
      state = "rejected"
    } else if (idx < currentIdx) {
      state = "approved"
    } else if (idx === currentIdx) {
      state = "current"
    } else {
      state = "pending"
    }
    return {
      label: stage.label,
      state,
      actor: rec?.actor,
      timestamp: rec?.at ? fmtDateTime(rec.at) : undefined,
      comment: rec?.comment,
    }
  })
}

export interface ApplicationDetailProps {
  app: Application
  /** Advance to the next stage, recording actor + timestamp. */
  onAdvance: (next: AppStatus, stage: StageId) => void
  /** Send the application back to 書類審査 as 要確認, with a reason. */
  onSendBack: (reason: string) => void
  /** Verify/unverify a required document for the 本人確認 checklist. */
  onToggleDoc: (doc: string, on: boolean) => void
  /** Record the ID-verification method. */
  onSetIdMethod: (method: string) => void
  /** Change requested copies (drives fee). */
  onSetCopies: (copies: number) => void
  /** Record the signed issuance. */
  onIssue: () => void
}

export function ApplicationDetail({
  app,
  onAdvance,
  onSendBack,
  onToggleDoc,
  onSetIdMethod,
  onSetCopies,
  onIssue,
}: ApplicationDetailProps) {
  const kind = APP_KINDS[app.kind]
  const statusMeta = APP_STATUSES[app.status]

  const allDocsVerified = kind.requiredDocs.every((d) => app.verifiedDocs.includes(d))
  const idVerified = Boolean(app.idMethod && app.idMethod.trim().length > 0)
  const fee = calcFee(app.kind, app.copies)

  const [sendBackReason, setSendBackReason] = React.useState("")
  const [showSendBack, setShowSendBack] = React.useState(false)

  const steps = buildSteps(app)

  // --- Stage transition logic (the hand-rolled state machine ApprovalSteps does not provide) ---
  const advance = () => {
    switch (app.status) {
      case "uketsuke":
        onAdvance("honnin_machi", "uketsuke")
        break
      case "honnin_machi":
        onAdvance("shinsa", "honnin")
        break
      case "shinsa":
      case "kakunin":
        onAdvance("shonin_machi", "shinsa")
        break
      // 承認 (shonin_machi → kofu_junbi) は CoSign 経由なのでここでは扱わない
      case "kofu_junbi":
        onAdvance("kofu_zumi", "kofu")
        break
    }
  }

  // ボタンのラベルと活性条件 (advance button label + gating per stage)
  let advanceLabel: string | null = null
  let advanceDisabled = false
  let advanceHint: string | null = null
  switch (app.status) {
    case "uketsuke":
      advanceLabel = "本人確認へ進む"
      break
    case "honnin_machi":
      advanceLabel = "書類審査へ進む"
      advanceDisabled = !idVerified || !allDocsVerified
      if (advanceDisabled) advanceHint = "本人確認の方法と必要書類をすべて確認してください。"
      break
    case "shinsa":
    case "kakunin":
      advanceLabel = "承認へ回す"
      break
    case "kofu_junbi":
      advanceLabel = "交付（証明書発行）へ進む"
      break
    default:
      advanceLabel = null
  }

  const canSendBack =
    app.status === "shinsa" || app.status === "shonin_machi" || app.status === "kofu_junbi"

  // CoSign gate for 承認 (shonin_machi). When the 2人目 signs, advance to 交付準備.
  const handleCoSign = () => {
    onAdvance("kofu_junbi", "shonin")
  }

  // SignedRecord drives the 交付 issuance. status reflects whether already issued.
  const signedValue: SignedRecordValue = {
    status: app.issued ? "signed" : "draft",
    signedBy: app.issued?.by,
    signedAt: app.issued?.at,
    addenda: [],
  }
  const handleSignedChange = (v: SignedRecordValue) => {
    if (v.status === "signed" && !app.issued) onIssue()
  }

  return (
    <div className="flex flex-col gap-5">
      {/* 申請ヘッダ (header) */}
      <div className="flex flex-col gap-2">
        <div className="flex flex-wrap items-center gap-2">
          <Badge variant={statusMeta.tone} icon={<StatusIcon status={app.status} />}>
            {statusMeta.label}
          </Badge>
          <SlaBadge dueAt={app.dueAt} />
        </div>
        <p className="text-sm text-muted-foreground">受付番号 {app.receiptNo}</p>
      </div>

      {app.status === "kakunin" ? (
        <Alert variant="warning">
          <IconAlertTriangle aria-hidden="true" />
          <AlertTitle>要確認 — 書類審査で差戻し</AlertTitle>
          <AlertDescription>
            {app.stages.shinsa?.comment ?? "確認事項があります。内容を確認のうえ再審査へ回してください。"}
          </AlertDescription>
        </Alert>
      ) : null}

      <MetadataList
        items={[
          { label: "申請種別", value: kind.label },
          { label: "申請者", value: `${app.applicant}（${app.furigana}）` },
          { label: "受付日時", value: fmtDateTime(app.receivedAt) },
          { label: "処理期限", value: fmtDateTime(app.dueAt) },
          { label: "標準処理時間", value: `${kind.slaHours} 時間` },
        ]}
      />

      <Separator />

      {/* 処理ワークフロー (workflow) */}
      <section aria-labelledby="wf-heading" className="flex flex-col gap-3">
        <h3 id="wf-heading" className="text-base font-semibold">
          処理ワークフロー
        </h3>
        <ApprovalSteps
          steps={steps}
          stateLabels={{
            pending: "未着手",
            current: "対応中",
            approved: "完了",
            rejected: "差戻し",
            skipped: "スキップ",
          }}
        />

        {/* advance / send-back controls */}
        {app.status !== "kofu_zumi" ? (
          <div className="flex flex-col gap-2">
            {advanceHint ? (
              <p className="text-xs text-warning">{advanceHint}</p>
            ) : null}
            <div className="flex flex-wrap gap-2">
              {advanceLabel && app.status !== "shonin_machi" ? (
                <Button onClick={advance} disabled={advanceDisabled}>
                  <IconArrowRight className="h-4 w-4" aria-hidden="true" />
                  {advanceLabel}
                </Button>
              ) : null}
              {canSendBack ? (
                <Button variant="outline" onClick={() => setShowSendBack((s) => !s)}>
                  <IconArrowBackUp className="h-4 w-4" aria-hidden="true" />
                  差戻し
                </Button>
              ) : null}
            </div>
            {showSendBack ? (
              <div className="flex flex-col gap-2 rounded-lg border border-border p-3">
                <Textarea
                  label="差戻し理由"
                  rows={2}
                  value={sendBackReason}
                  onChange={(e) => setSendBackReason(e.target.value)}
                  placeholder="例）委任状の代理人欄に押印がありません。"
                />
                <div className="flex justify-end gap-2">
                  <Button variant="ghost" size="sm" onClick={() => setShowSendBack(false)}>
                    キャンセル
                  </Button>
                  <Button
                    variant="warning"
                    size="sm"
                    disabled={!sendBackReason.trim()}
                    onClick={() => {
                      onSendBack(sendBackReason.trim())
                      setSendBackReason("")
                      setShowSendBack(false)
                    }}
                  >
                    要確認として差戻し
                  </Button>
                </div>
              </div>
            ) : null}
          </div>
        ) : null}
      </section>

      <Separator />

      {/* 本人確認 + 必要書類チェック (identity & documents) */}
      <section aria-labelledby="id-heading" className="flex flex-col gap-3">
        <h3 id="id-heading" className="inline-flex items-center gap-1.5 text-base font-semibold">
          <IconId className="h-4 w-4" aria-hidden="true" />
          本人確認・必要書類チェック
        </h3>

        <div className="flex flex-col gap-1.5">
          <label htmlFor="id-method" className="text-sm font-medium leading-none">
            本人確認の方法
          </label>
          {/* native select wrapped by Select would also work; using a controlled input list */}
          <select
            id="id-method"
            className="inline-flex h-9 w-full appearance-none items-center rounded-lg border border-input bg-transparent px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-ring disabled:opacity-50"
            value={app.idMethod ?? ""}
            disabled={Boolean(app.issued)}
            onChange={(e) => onSetIdMethod(e.target.value)}
          >
            <option value="">未確認</option>
            <option value="マイナンバーカード">マイナンバーカード</option>
            <option value="運転免許証">運転免許証</option>
            <option value="パスポート">パスポート</option>
            <option value="在留カード">在留カード</option>
            <option value="健康保険証 + 補助書類">健康保険証 + 補助書類</option>
          </select>
        </div>

        <fieldset className="flex flex-col gap-2">
          <legend className="mb-1 text-sm font-medium">必要書類（{kind.label}）</legend>
          {kind.requiredDocs.map((doc) => (
            <Checkbox
              key={doc}
              label={doc}
              checked={app.verifiedDocs.includes(doc)}
              disabled={Boolean(app.issued)}
              onCheckedChange={(on) => onToggleDoc(doc, on)}
            />
          ))}
        </fieldset>

        <div
          className={
            "inline-flex w-fit items-center gap-1.5 rounded-md px-2.5 py-1 text-xs font-medium " +
            (idVerified && allDocsVerified
              ? "bg-success-subtle text-success-subtle-foreground"
              : "bg-warning-subtle text-warning-subtle-foreground")
          }
        >
          <IconClipboardCheck className="h-3.5 w-3.5" aria-hidden="true" />
          {idVerified && allDocsVerified
            ? "本人確認・必要書類すべて確認済"
            : "未確認の項目があります"}
        </div>
      </section>

      <Separator />

      {/* 手数料計算 (fee) */}
      <section aria-labelledby="fee-heading" className="flex flex-col gap-3">
        <h3 id="fee-heading" className="inline-flex items-center gap-1.5 text-base font-semibold">
          <IconReceipt2 className="h-4 w-4" aria-hidden="true" />
          手数料計算
        </h3>
        <div className="grid gap-3 sm:grid-cols-2">
          <NumberInput
            label="部数"
            layout="stepper"
            min={1}
            max={20}
            value={app.copies}
            disabled={Boolean(app.issued)}
            onValueChange={(n) => onSetCopies(Math.max(1, n))}
          />
          <Statistic
            label={`手数料合計（1通 ${formatCurrency(kind.unitFee)} × ${app.copies}通）`}
            value={formatCurrency(fee)}
          />
        </div>
      </section>

      <Separator />

      {/* 承認 (approval) — 2人確認 via CoSign, only at 承認待ち */}
      {app.status === "shonin_machi" ? (
        <section aria-labelledby="approve-heading" className="flex flex-col gap-3">
          <h3 id="approve-heading" className="text-base font-semibold">
            承認（責任者2人確認）
          </h3>
          <Card>
            <CardContent className="pt-6">
              <CoSign
                primaryId={CURRENT_STAFF}
                requireReason={false}
                signerLabel="承認責任者ID（係長・課長補佐等）"
                attestations={[
                  { id: "id-ok", label: "本人確認・必要書類を確認した" },
                  { id: "fee-ok", label: `手数料 ${formatCurrency(fee)} を確認した` },
                  { id: "content-ok", label: "申請内容に誤りがないことを確認した" },
                ]}
                labels={{ sign: "承認する（2人確認）" }}
                onSign={handleCoSign}
              />
            </CardContent>
          </Card>
        </section>
      ) : null}

      {/* 交付 / 証明書発行 (issuance) — SignedRecord, at 交付準備 or 交付済 */}
      {app.status === "kofu_junbi" || app.status === "kofu_zumi" ? (
        <section aria-labelledby="issue-heading" className="flex flex-col gap-3">
          <h3 id="issue-heading" className="text-base font-semibold">
            交付・証明書発行
          </h3>
          <Card>
            <CardHeader>
              <CardTitle as="h4" className="text-base">
                交付記録
              </CardTitle>
            </CardHeader>
            <CardContent>
              <SignedRecord
                value={signedValue}
                onChange={handleSignedChange}
                signerId={CURRENT_STAFF}
                canSign={app.status === "kofu_junbi"}
                labels={{
                  draft: "交付前（未発行）",
                  signed: "交付・発行済",
                  sign: "交付（証明書を発行）",
                  locked: "交付済みの記録は変更できません。訂正は追記で行います。",
                  signedByLabel: "交付担当",
                  addendaTitle: "交付後の追記",
                  addendum: "追記する",
                }}
              >
                {({ readOnly }) => (
                  <MetadataList
                    items={[
                      { label: "証明書", value: `${kind.label} ${app.copies}通` },
                      { label: "手数料", value: formatCurrency(fee) },
                      { label: "申請者", value: app.applicant },
                      {
                        label: "交付方法",
                        value: readOnly ? "窓口交付" : "窓口交付（発行時に確定）",
                      },
                    ]}
                  />
                )}
              </SignedRecord>
            </CardContent>
          </Card>
        </section>
      ) : null}

      {app.status === "kofu_zumi" ? (
        <Alert variant="success">
          <IconClipboardCheck aria-hidden="true" />
          <AlertTitle>交付完了</AlertTitle>
          <AlertDescription>
            この申請は交付済みです（交付 {app.issued ? fmtDateTime(app.issued.at) : ""} ／
            {app.issued?.by}）。
          </AlertDescription>
        </Alert>
      ) : null}

    </div>
  )
}

// --- small presentational helpers (status icon + sla badge) ---

export function StatusIcon({ status }: { status: AppStatus }) {
  const cls = "h-3 w-3"
  switch (status) {
    case "uketsuke":
      return <IconCircleDot className={cls} />
    case "honnin_machi":
      return <IconUserCheck className={cls} />
    case "shinsa":
      return <IconSearch className={cls} />
    case "kakunin":
      return <IconAlertTriangle className={cls} />
    case "shonin_machi":
      return <IconRubberStamp className={cls} />
    case "kofu_junbi":
      return <IconPackage className={cls} />
    case "kofu_zumi":
      return <IconCircleCheck className={cls} />
  }
}

export function SlaBadge({ dueAt }: { dueAt: string }) {
  const state = slaState(dueAt, NOW)
  if (state === "overdue") {
    return (
      <Badge variant="destructive" icon={<IconAlertTriangle className="h-3 w-3" />}>
        期限超過
      </Badge>
    )
  }
  if (state === "at_risk") {
    return (
      <Badge variant="warning" icon={<IconAlertTriangle className="h-3 w-3" />}>
        期限間近
      </Badge>
    )
  }
  return (
    <Badge variant="outline" icon={<IconCircleCheck className="h-3 w-3" />}>
      期限内
    </Badge>
  )
}

