/** Map an application status to the index of the stage currently in progress. */
export function statusToStageIndex(status: AppStatus): number {
  switch (status) {
    case "uketsuke":
      return 0 // 受付 done, 本人確認 next — stage 0 complete, current = 1
    case "honnin_machi":
