/** 手数料計算 (fee calc): 1通 unitFee × copies */
export function calcFee(kind: AppKind, copies: number): number {
  return APP_KINDS[kind].unitFee * copies
}

/** SLA 状態 (deadline flag) relative to `now`. */
export type SlaState = "overdue" | "at_risk" | "ok"
export function slaState(dueAtISO: string, now: Date): SlaState {
  const due = new Date(dueAtISO).getTime()
  const ms = due - now.getTime()
  if (ms < 0) return "overdue"
  if (ms < 60 * 60 * 1000) return "at_risk" // 残り1時間未満
  return "ok"
}

